// Error types
pyo3::create_exception!(_spikard, ExecutionError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SchemaBuildError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, RequestHandlingError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SerializationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, JsonError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ValidationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ParseError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, AuthenticationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, AuthorizationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, NotFoundError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, RateLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, InvalidInputError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ComplexityLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, DepthLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, InternalError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, GraphQLError, pyo3::exceptions::PyException);

/// Convert a `spikard_graphql::GraphQLError` error to a Python exception.
fn graph_q_l_error_to_py_err(e: spikard_graphql::GraphQLError) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard_graphql::GraphQLError::ExecutionError(..) => ExecutionError::new_err(msg),
        spikard_graphql::GraphQLError::SchemaBuildError(..) => SchemaBuildError::new_err(msg),
        spikard_graphql::GraphQLError::RequestHandlingError(..) => RequestHandlingError::new_err(msg),
        spikard_graphql::GraphQLError::SerializationError(..) => SerializationError::new_err(msg),
        spikard_graphql::GraphQLError::JsonError(..) => JsonError::new_err(msg),
        spikard_graphql::GraphQLError::ValidationError(..) => ValidationError::new_err(msg),
        spikard_graphql::GraphQLError::ParseError(..) => ParseError::new_err(msg),
        spikard_graphql::GraphQLError::AuthenticationError(..) => AuthenticationError::new_err(msg),
        spikard_graphql::GraphQLError::AuthorizationError(..) => AuthorizationError::new_err(msg),
        spikard_graphql::GraphQLError::NotFound(..) => NotFoundError::new_err(msg),
        spikard_graphql::GraphQLError::RateLimitExceeded(..) => RateLimitExceededError::new_err(msg),
        spikard_graphql::GraphQLError::InvalidInput { .. } => InvalidInputError::new_err(msg),
        spikard_graphql::GraphQLError::ComplexityLimitExceeded => ComplexityLimitExceededError::new_err(msg),
        spikard_graphql::GraphQLError::DepthLimitExceeded => DepthLimitExceededError::new_err(msg),
        spikard_graphql::GraphQLError::InternalError(..) => InternalError::new_err(msg),
        _ => GraphQLError::new_err(msg),
    }
}

// Error types
pyo3::create_exception!(_spikard, BuildingFailedError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SchemaError, pyo3::exceptions::PyException);

/// Convert a `spikard_graphql::SchemaError` error to a Python exception.
fn schema_error_to_py_err(e: spikard_graphql::SchemaError) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard_graphql::SchemaError::BuildingFailed(..) => BuildingFailedError::new_err(msg),
        spikard_graphql::SchemaError::ValidationError(..) => ValidationError::new_err(msg),
        spikard_graphql::SchemaError::ComplexityLimitExceeded { .. } => ComplexityLimitExceededError::new_err(msg),
        spikard_graphql::SchemaError::DepthLimitExceeded { .. } => DepthLimitExceededError::new_err(msg),
        _ => SchemaError::new_err(msg),
    }
}

